import{_ as t,c as e,o as a,ag as r}from"./chunks/framework.B0zzL8Pn.js";const _=JSON.parse('{"title":"BGP (Border Gateway Protocol)","description":"","frontmatter":{},"headers":[],"relativePath":"Tech/~/network/bgp.md","filePath":"Tech/~/network/bgp.md","lastUpdated":1774964361000}'),p={name:"Tech/~/network/bgp.md"};function l(n,o,s,i,c,d){return a(),e("div",null,o[0]||(o[0]=[r('<h1 id="bgp-border-gateway-protocol" tabindex="-1">BGP (Border Gateway Protocol) <a class="header-anchor" href="#bgp-border-gateway-protocol" aria-label="Permalink to &quot;BGP (Border Gateway Protocol)&quot;">​</a></h1><p>자격증 공부하면서 달달 외웠던 IGP, BGP의 그 BGP가 맞다</p><p>BGP는 서로다른 <strong>AS</strong> 간에 경로 정보를 교환하는 프로토콜이다.</p><h2 id="as" tabindex="-1">AS <a class="header-anchor" href="#as" aria-label="Permalink to &quot;AS&quot;">​</a></h2><p>AS(Autonomous System)는 자율 시스템의 약자로 단일 관리 주체 하에서 <strong>일관된 라우팅 정책</strong>을 적용받는 라우터(네트워크) 집단을 의미한다.</p><p>인터넷은 전세계 수많은 네트워크가 연결된 구조이다.<br> 이러한 대규모 네트워크를 효율적으로 관리하기 위해 여러개의 AS로 나뉘어 운영이됨</p><p>여기서 말하는 &quot;정책&quot;은 라우팅할 때 어떤 기준으로 어떤 경로를 사용해야 할지에 대한 규칙을 말함</p><ul><li>비용 문제 (Transit 비용)</li><li>성능 문제 (지연 최소화)</li><li>비즈니스 문제</li></ul><p>이와 같은 다양한 요소에 따라 각 AS는 서로 다른 정책을 가지며,<br> 이 때문에 AS는 단순 네트워크 집합이 아니라 정책 단위라고 할 수 있다</p><p>AS는 각각의 고유번호를 지니는데 이를 <strong>ASN</strong>이라고 한다</p><ul><li>ex) KT: AS4766, AWS: AS16509</li><li>BGP에서 이 번호로 서로 식별함</li></ul><p>AS 간에는 BGP(Border Gateway Protocol)를 통해 라우팅 정보를 교환하며, 각 AS는 자신의 정책에 따라 최적의 경로를 선택한다.</p><p>자율 시스템이라고 하는 이유는 AS 내부에서는 독립적으로 라우팅 정책을 결정할 수 있기 때문</p><p>인터넷 자체가 중앙에서 통제하는 개념이 아님, 각 AS가 본인들만의 정책을 설정하여 이를 자율 시스템이라고 함</p>',14)]))}const A=t(p,[["render",l]]);export{_ as __pageData,A as default};
